UPDATE public.regions SET climate_data = '{"intro": {"headline": "Climate Snapshot: A Year in Calabria", "tagline": "A peninsula of two seas and one mountain spine, where the weather is a story of dramatic contrasts.", "paragraphs": ["I''ve come to think of Calabria''s climate not as a single thing, but as a conversation between three voices. There''s the Tyrrhenian, soft and warm, with light that feels almost African in summer. There''s the Ionian, brisker, with a different kind of blue. And in between, the Sila and Aspromonte mountains, which can be cloaked in deep snow while the coasts below remain bathed in sun. The wind, the ''ponente'' or the ''scirocco'', is a constant character.", "The year unfolds in distinct chapters. Spring is a riot of green and wildflowers, brief but spectacular. Summer is long, hot, and dry on the coast — the kind of heat that flattens you between 1 and 5 PM, demanding a respect for the riposo. Autumn is, for me, the masterpiece: the light turns golden, the sea is still warm enough to swim in October, and the chestnut woods of the Sila explode in color. Winter is mild by the sea but can be genuinely cold and snowy inland.", "Practically, this means you must choose your altitude as carefully as your view. Living in Tropea is a different climate from living in Cosenza, just an hour away. The summer is for early mornings and long evenings; the winter, for sturdy shoes and wool. It is not a place of perpetual spring, but of profound seasons."], "hoverQuote": "In Calabria, the weather doesn''t change. It performs.", "ctaText": "Slide through the seasons →"}, "regions": {"cosenza": {"name": "Cosenza", "type": "inland", "palette": "urban"}, "reggio": {"name": "Reggio Calabria", "type": "coastal", "palette": "coastal"}, "tropea": {"name": "Tropea", "type": "beach", "palette": "coastal"}, "catanzaro": {"name": "Catanzaro", "type": "hilltop", "palette": "urban"}}, "months": [{"month": "January", "index": 0, "season": "winter", "cosenza": {"tempLow": 3, "tempHigh": 12, "rainfall": 90, "sunHours": 4}, "reggio": {"tempLow": 8, "tempHigh": 14, "rainfall": 110, "sunHours": 4}, "tropea": {"tempLow": 7, "tempHigh": 14, "rainfall": 100, "sunHours": 4}, "catanzaro": {"tempLow": 6, "tempHigh": 13, "rainfall": 130, "sunHours": 4}, "tooltip": "Crisp air, citrus harvest, snow on the Sila", "culturalEvent": "The citrus harvest is in full swing, perfuming the air.", "culturalEventUrl": "", "visualCue": "Snow-dusted peaks of the Sila over a green coastal plain"}, {"month": "February", "index": 1, "season": "winter", "cosenza": {"tempLow": 3, "tempHigh": 13, "rainfall": 80, "sunHours": 5}, "reggio": {"tempLow": 8, "tempHigh": 15, "rainfall": 90, "sunHours": 5}, "tropea": {"tempLow": 7, "tempHigh": 15, "rainfall": 85, "sunHours": 5}, "catanzaro": {"tempLow": 6, "tempHigh": 14, "rainfall": 110, "sunHours": 5}, "tooltip": "Almond blossoms, carnival begins", "culturalEvent": "Carnevale celebrations across Calabria, especially in Castrovillari.", "culturalEventUrl": "", "visualCue": "Pink and white blossoms of almond trees against bare branches"}, {"month": "March", "index": 2, "season": "spring", "cosenza": {"tempLow": 5, "tempHigh": 16, "rainfall": 70, "sunHours": 6}, "reggio": {"tempLow": 9, "tempHigh": 17, "rainfall": 70, "sunHours": 6}, "tropea": {"tempLow": 9, "tempHigh": 17, "rainfall": 65, "sunHours": 6}, "catanzaro": {"tempLow": 8, "tempHigh": 16, "rainfall": 90, "sunHours": 6}, "tooltip": "Wildflowers explode, Easter approaches", "culturalEvent": "Holy Week (''Settimana Santa'') processions begin in many towns.", "culturalEventUrl": "", "visualCue": "Hillsides covered in poppies, daisies, and yellow broom"}, {"month": "April", "index": 3, "season": "spring", "cosenza": {"tempLow": 7, "tempHigh": 19, "rainfall": 65, "sunHours": 7}, "reggio": {"tempLow": 11, "tempHigh": 20, "rainfall": 50, "sunHours": 7}, "tropea": {"tempLow": 11, "tempHigh": 19, "rainfall": 50, "sunHours": 7}, "catanzaro": {"tempLow": 10, "tempHigh": 1